// NewCmd creates the top-level `langsmith api` command.
func NewCmd() *cobra.Command {
	var (
		body    string
		headers []string
		include bool
		input   string
		method  string
		fields  []string
		raw     []string
	)

	cmd := &cobra.Command{
		Use:   "api",
		Short: "Browse API endpoints and make authenticated requests",
		Long: `Browse LangSmith API endpoints and make authenticated HTTP requests.

Browse endpoints:
  langsmith api ls                              List all endpoints
  langsmith api ls --tag datasets               Filter by tag
  langsmith api ls --search create              Search endpoints
  langsmith api info GET sessions               Show endpoint details

Make requests:
  langsmith api sessions?limit=5
  langsmith api runs/query -F 'session[]=abc' -F limit=10
  langsmith api sessions/abc-123 -X DELETE
  langsmith api datasets --input body.json
  echo '{"name":"x"}' | langsmith api sessions --input -
  langsmith api sessions --include`,
		Args: cobra.ArbitraryArgs,
		RunE: func(cmd *cobra.Command, args []string) error {
			if len(args) < 1 {
				return cmd.Help()
			}

			params, err := parseFields(raw, fields)
			if err != nil {
				return err
			}

			methodPassed := cmd.Flags().Changed("method")
			method := strings.ToUpper(method)
			if !methodPassed && (len(params) > 0 || input != "" || body != "") {
				method = "POST"
			}
			if !isHTTPMethod(method) {
				return fmt.Errorf("invalid HTTP method: %q\nRun 'langsmith api --help' for usage", method)
			}

			path := args[0]

			c, err := cmdutil.GetClient(cmd)
			if err != nil {
				return err
			}

			w := cmd.OutOrStdout()
			statusCode, err := runRequest(c, method, path, body, input, params, headers, include, w)
			if err != nil {
				return err
			}
			if statusCode >= 400 {
				return fmt.Errorf("HTTP %d", statusCode)
			}
			return nil
		},
	}

	// Flags for request mode
	cmd.Flags().StringVar(&body, "body", "", `Request body (JSON string, @file, or @- for stdin)`)
	cmd.Flags().StringVar(&input, "input", "", `File to use as body for the HTTP request (use "-" to read from stdin)`)
	cmd.Flags().StringArrayVarP(&fields, "field", "F", nil, `Add a typed JSON field in key=value format (use "@<path>" or "@-" to read value from file or stdin)`)
	cmd.Flags().StringArrayVarP(&raw, "raw-field", "f", nil, "Add a string JSON field in key=value format")
	cmd.Flags().StringArrayVarP(&headers, "header", "H", nil, "Additional headers (Key:Value, repeatable)")
	cmd.Flags().BoolVarP(&include, "include", "i", false, "Include HTTP response headers in output")
	cmd.Flags().StringVarP(&method, "method", "X", "GET", "HTTP method")

	cmd.AddCommand(newLsCmd())
	cmd.AddCommand(newInfoCmd())

	return cmd
}

package structured

import (
	"context"

	"github.com/spf13/cobra"
)

type Command[I any] struct {
	Use          string
	Short        string
	Long         string
	Args         cobra.PositionalArgs
	Input        func(*cobra.Command) I
	Action       func(context.Context, *cobra.Command, I, []string) (any, error)
	Render       Spec
	CustomOutput bool
}

func (c Command[I]) Cobra() *cobra.Command {
	var input I
	cmd := &cobra.Command{
		Use:   c.Use,
		Short: c.Short,
		Long:  c.Long,
		Args:  c.Args,
		RunE: func(cmd *cobra.Command, args []string) error {
			result, err := c.Action(cmd.Context(), cmd, input, args)
			if err != nil {
				return err
			}
			if c.CustomOutput {
				return nil
			}
			return Render(cmd, result, c.Render)
		},
	}
	if c.Input != nil {
		input = c.Input(cmd)
	}
	if !c.CustomOutput {
		cmd.Flags().String("jq", "", "Filter JSON output using a jq expression")
	}
	return cmd
}

type Parent struct {
	Use      string
	Short    string
	Long     string
	Children []func() *cobra.Command
}

func (p Parent) Cobra() *cobra.Command {
	cmd := &cobra.Command{
		Use:   p.Use,
		Short: p.Short,
		Long:  p.Long,
	}
	for _, child := range p.Children {
		cmd.AddCommand(child())
	}
	return cmd
}

package cache

import (
	"crypto/sha256"
	"fmt"
	"os"
	"path/filepath"
	"time"
)

// DefaultDir returns ~/.langsmith/cache.
func DefaultDir() string {
	home, err := os.UserHomeDir()
	if err != nil {
		return filepath.Join(os.TempDir(), "langsmith-cache")
	}
	return filepath.Join(home, ".langsmith", "cache")
}

// PathForKey returns a cache file path using a SHA256 hash of the key.
func PathForKey(dir, prefix, key string) string {
	h := sha256.Sum256([]byte(key))
	name := fmt.Sprintf("%s-%x.json", prefix, h[:8])
	return filepath.Join(dir, name)
}

// ReadIfFresh reads a cached file if it exists and is within TTL.
func ReadIfFresh(path string, ttl time.Duration) ([]byte, error) {
	info, err := os.Stat(path)
	if err != nil {
		return nil, err
	}
	if time.Since(info.ModTime()) > ttl {
		_ = os.Remove(path)
		return nil, fmt.Errorf("cache expired")
	}
	return os.ReadFile(path)
}

// Write writes data to a cache file, creating parent directories as needed.
func Write(path string, data []byte) error {
	if err := os.MkdirAll(filepath.Dir(path), 0755); err != nil {
		return err
	}
	return os.WriteFile(path, data, 0644)
}

package extract

import (
	"fmt"
	"strconv"
	"time"

	langsmith "github.com/langchain-ai/langsmith-go"
)

// ExtractRun normalizes a LangSmith RunQueryResponseRun to a flat map.
// This mirrors the Python extract_run() function exactly.
func ExtractRun(run langsmith.RunSchema, includeMetadata, includeIO, includeFeedback bool) map[string]any {
	result := map[string]any{
		"run_id":        run.ID,
		"trace_id":      run.TraceID,
		"name":          run.Name,
		"run_type":      string(run.RunType),
		"parent_run_id": nilIfEmpty(run.ParentRunID),
		"start_time":    formatTime(run.StartTime),
		"end_time":      formatTimeNullable(run.EndTime),
	}

	if includeMetadata {
		durationMs := calcDuration(run.StartTime, run.EndTime)

		var customMetadata map[string]any
		if run.Extra != nil {
			if md, ok := run.Extra["metadata"]; ok {
				if mdMap, ok := md.(map[string]any); ok {
					customMetadata = mdMap
				}
			}
		}

		var tokenUsage map[string]any
		if run.PromptTokens > 0 || run.CompletionTokens > 0 || run.TotalTokens > 0 {
			tokenUsage = map[string]any{}
			if run.PromptTokens > 0 {
				tokenUsage["prompt_tokens"] = run.PromptTokens
			}
			if run.CompletionTokens > 0 {
				tokenUsage["completion_tokens"] = run.CompletionTokens
			}
			if run.TotalTokens > 0 {
				tokenUsage["total_tokens"] = run.TotalTokens
			}
		}

		var costs map[string]any
		if run.PromptCost != "" || run.CompletionCost != "" || run.TotalCost != "" {
			costs = map[string]any{}
			if f, err := strconv.ParseFloat(run.PromptCost, 64); err == nil && f > 0 {
				costs["prompt_cost"] = f
			}
			if f, err := strconv.ParseFloat(run.CompletionCost, 64); err == nil && f > 0 {
				costs["completion_cost"] = f
			}
			if f, err := strconv.ParseFloat(run.TotalCost, 64); err == nil && f > 0 {
				costs["total_cost"] = f
			}
		}
		if len(costs) == 0 {
			costs = nil
		}

		var tags any
		if len(run.Tags) > 0 {
			tags = run.Tags
		}

		result["status"] = run.Status
		result["duration_ms"] = durationMs
		result["custom_metadata"] = customMetadata
		result["token_usage"] = tokenUsage
		result["costs"] = costs
		result["tags"] = tags
	}

	if includeIO {
		result["inputs"] = nilIfEmptyMap(run.Inputs)
		result["outputs"] = nilIfEmptyMap(run.Outputs)
		result["error"] = nilIfEmpty(run.Error)
	}

	if includeFeedback {
		var feedbackStats any
		if len(run.FeedbackStats) > 0 {
			feedbackStats = run.FeedbackStats
		}
		result["feedback_stats"] = feedbackStats
	}

	return result
}

// calcDuration returns duration in milliseconds, or nil.
func calcDuration(start time.Time, end time.Time) any {
	if start.IsZero() || end.IsZero() {
		return nil
	}
	return int64(end.Sub(start).Milliseconds())
}

func formatTime(t time.Time) any {
	if t.IsZero() {
		return nil
	}
	return t.Format(time.RFC3339Nano)
}

func formatTimeNullable(t time.Time) any {
	if t.IsZero() {
		return nil
	}
	return t.Format(time.RFC3339Nano)
}

func nilIfEmpty(s string) any {
	if s == "" {
		return nil
	}
	return s
}

func nilIfEmptyMap(m map[string]any) any {
	if len(m) == 0 {
		return nil
	}
	return m
}

// FormatDurationHuman formats milliseconds as human-readable string.
func FormatDurationHuman(ms int64) string {
	if ms < 1000 {
		return fmt.Sprintf("%dms", ms)
	}
	return fmt.Sprintf("%.2fs", float64(ms)/1000.0)
}

package cmdutil

import (
	"context"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"net/url"
	"os"
	"strings"
	"time"

	"github.com/langchain-ai/langsmith-cli/internal/client"
	lsconfig "github.com/langchain-ai/langsmith-cli/internal/config"
	"github.com/spf13/cobra"
)

const oauthClientID = "langsmith-cli"

type oauthTokenResponse struct {
	AccessToken  string `json:"access_token"`
	ExpiresIn    int    `json:"expires_in"`
	RefreshToken string `json:"refresh_token"`
}

type oauthErrorResponse struct {
	Code             string `json:"error"`
	ErrorDescription string `json:"error_description"`
}

func (e *oauthErrorResponse) Error() string {
	if e.ErrorDescription == "" {
		return e.Code
	}
	return e.Code + ": " + e.ErrorDescription
}

// getFlagString looks up a string flag by checking Flags() (which includes
// inherited persistent flags for child commands) and then PersistentFlags()
// (which covers the root command itself where persistent flags are not yet
// merged into Flags()).
func getFlagString(cmd *cobra.Command, name string) string {
	if f := cmd.Flags().Lookup(name); f != nil {
		return f.Value.String()
	}
	if f := cmd.PersistentFlags().Lookup(name); f != nil {
		return f.Value.String()
	}
	return ""
}

func isFlagChanged(cmd *cobra.Command, name string) bool {
	if f := cmd.Flags().Lookup(name); f != nil {
		return f.Changed
	}
	if f := cmd.PersistentFlags().Lookup(name); f != nil {
		return f.Changed
	}
	return false
}

// ResolveAPIKey reads the API key from cobra's flag tree → env.
func ResolveAPIKey(cmd *cobra.Command) string {
	if v := getFlagString(cmd, "api-key"); v != "" {
		return v
	}
	return os.Getenv("LANGSMITH_API_KEY")
}

// ResolveAPIURL reads the API URL from cobra's flag tree → env → default.
func ResolveAPIURL(cmd *cobra.Command) string {
	if v := getFlagString(cmd, "api-url"); v != "" {
		return client.NormalizeURL(v)
	}
	if v := os.Getenv("LANGSMITH_ENDPOINT"); v != "" {
		return client.NormalizeURL(v)
	}
	return "https://api.smith.langchain.com"
}

// ResolveFormat reads the output format from cobra's flag tree.
func ResolveFormat(cmd *cobra.Command) string {
	v := getFlagString(cmd, "format")
	if v == "" {
		return "pretty"
	}
	return v
}

// ResolveJQ reads the jq filter from cobra's flag tree.
func ResolveJQ(cmd *cobra.Command) string {
	return getFlagString(cmd, "jq")
}

// GetClient creates a LangSmith client from cobra flags, returning an error
// if no API key or OAuth access token is available.
func GetClient(cmd *cobra.Command) (*client.Client, error) {
	opts, err := ResolveClientOptions(cmd, true)
	if err != nil {
		return nil, err
	}
	if opts.APIKey == "" && opts.OAuthAccessToken == "" {
		return nil, fmt.Errorf("not authenticated; run 'langsmith login', set LANGSMITH_API_KEY, or pass --api-key")
	}
	return client.NewWithOptions(opts), nil
}

// ResolveClientOptions resolves auth/routing from cobra flags, env, and saved
// profiles. This mirrors the top-level CLI auth behavior for standalone
// helpers such as `langsmith api`.
func ResolveClientOptions(cmd *cobra.Command, refreshOAuth bool) (client.Options, error) {
	opts := client.Options{APIURL: lsconfig.DefaultAPIURL}

	cfg, err := lsconfig.Load()
	var cfgErr error
	if err != nil {
		cfgErr = err
		cfg = &lsconfig.Config{Profiles: make(map[string]lsconfig.Profile)}
	}

	flagProfile := getFlagString(cmd, "profile")
	envProfile := strings.TrimSpace(os.Getenv("LANGSMITH_PROFILE"))
	profileName, profile, hasProfile := "", lsconfig.Profile{}, false
	if flagProfile != "" || envProfile != "" || cfgErr == nil {
		if cfgErr != nil && (flagProfile != "" || envProfile != "") {
			return opts, cfgErr
		}
		profileName, profile, hasProfile = cfg.ResolveProfile(flagProfile, envProfile)
		if (flagProfile != "" || envProfile != "") && !hasProfile {
			return opts, fmt.Errorf("profile not found: %s", profileName)
		}
	}

	if hasProfile {
		if profile.APIURL != "" {
			opts.APIURL = profile.APIURL
		}
		opts.WorkspaceID = profile.WorkspaceID
	}

	if v := os.Getenv("LANGSMITH_ENDPOINT"); v != "" {
		opts.APIURL = client.NormalizeURL(v)
	}
	if v := getFlagString(cmd, "api-url"); v != "" {
		opts.APIURL = client.NormalizeURL(v)
	}

	if v := os.Getenv("LANGSMITH_TENANT_ID"); v != "" {
		opts.WorkspaceID = v
	}
	if v := os.Getenv("LANGSMITH_WORKSPACE_ID"); v != "" {
		opts.WorkspaceID = v
	}
	if v := getFlagString(cmd, "workspace"); v != "" {
		opts.WorkspaceID = v
	} else if v := getFlagString(cmd, "workspace-id"); v != "" {
		opts.WorkspaceID = v
	}

	switch {
	case getFlagString(cmd, "api-key") != "":
		opts.APIKey = getFlagString(cmd, "api-key")
	case os.Getenv("LANGSMITH_API_KEY") != "":
		if isFlagChanged(cmd, "profile") {
			fmt.Fprintln(cmd.ErrOrStderr(), "warning: --profile was specified, but LANGSMITH_API_KEY is set and takes precedence over saved profile auth")
		}
		opts.APIKey = os.Getenv("LANGSMITH_API_KEY")
	case hasProfile && (profile.AccessToken() != "" || (refreshOAuth && profile.OAuth.RefreshToken != "")):
		if refreshOAuth && profile.OAuth.RefreshToken != "" &&
			(profile.AccessToken() == "" || profile.TokenExpiresSoon(time.Now(), time.Minute)) {
			ctx := cmd.Context()
			if ctx == nil {
				ctx = context.Background()
			}
			token, err := refreshProfileToken(ctx, opts.APIURL, profile.OAuth.RefreshToken)
			if err != nil {
				return opts, fmt.Errorf("refreshing OAuth token for profile %q: %w; run 'langsmith login --profile %s' to reauthenticate", profileName, err, profileName)
			}
			applyTokenResponse(&profile, token, time.Now())
			cfg.Profiles[profileName] = profile
			if err := cfg.Save(); err != nil {
				return opts, fmt.Errorf("saving refreshed OAuth token: %w", err)
			}
		}
		opts.ProfileName = profileName
		opts.OAuthAccessToken = profile.AccessToken()
	case hasProfile && profile.APIKey != "":
		opts.APIKey = profile.APIKey
	}
	if cfgErr != nil && opts.APIKey == "" {
		return opts, cfgErr
	}

	return opts, nil
}

func refreshProfileToken(ctx context.Context, apiURL, refreshToken string) (*oauthTokenResponse, error) {
	values := url.Values{
		"grant_type":    {"refresh_token"},
		"client_id":     {oauthClientID},
		"resource":      {oauthResource(apiURL)},
		"refresh_token": {refreshToken},
	}
	req, err := http.NewRequestWithContext(ctx, http.MethodPost, oauthURL(apiURL, "/oauth/token"), strings.NewReader(values.Encode()))
	if err != nil {
		return nil, fmt.Errorf("creating request: %w", err)
	}
	req.Header.Set("Content-Type", "application/x-www-form-urlencoded")

	resp, err := http.DefaultClient.Do(req)
	if err != nil {
		return nil, fmt.Errorf("sending request: %w", err)
	}
	defer resp.Body.Close()

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, fmt.Errorf("reading response: %w", err)
	}
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return nil, decodeOAuthError(body, resp.StatusCode)
	}
	var token oauthTokenResponse
	if err := json.Unmarshal(body, &token); err != nil {
		return nil, fmt.Errorf("decoding response: %w", err)
	}
	if token.AccessToken == "" {
		return nil, fmt.Errorf("token response did not include an access token")
	}
	return &token, nil
}

func applyTokenResponse(profile *lsconfig.Profile, token *oauthTokenResponse, now time.Time) {
	profile.OAuth.AccessToken = token.AccessToken
	if token.RefreshToken != "" {
		profile.OAuth.RefreshToken = token.RefreshToken
	}
	if token.ExpiresIn > 0 {
		profile.OAuth.ExpiresAt = now.Add(time.Duration(token.ExpiresIn) * time.Second).UTC().Format(time.RFC3339)
	}
}

func decodeOAuthError(body []byte, statusCode int) *oauthErrorResponse {
	var oauthErr oauthErrorResponse
	if err := json.Unmarshal(body, &oauthErr); err != nil || oauthErr.Code == "" {
		oauthErr = oauthErrorResponse{
			Code:             fmt.Sprintf("http_%d", statusCode),
			ErrorDescription: strings.TrimSpace(string(body)),
		}
	}
	return &oauthErr
}

func oauthURL(apiURL, path string) string {
	return strings.TrimRight(client.NormalizeURL(apiURL), "/") + path
}

// oauthResource is the API origin expected by the OAuth server; it must not
// include the /api/v1 suffix accepted by LANGSMITH_ENDPOINT.
func oauthResource(apiURL string) string {
	return strings.TrimRight(client.NormalizeURL(apiURL), "/")
}

